return [
  { json: { id: "windows", name: "Windows Desktop" } },
  { json: { id: "windows-server", name: "Windows Server" } },
  { json: { id: "macos", name: "macOS" } },
  { json: { id: "ubuntu", name: "Ubuntu Linux" } },
  { json: { id: "debian", name: "Debian Linux" } },
  { json: { id: "oracle-linux", name: "Oracle Linux" } },
  { json: { id: "rocky-linux", name: "Rocky Linux" } }
];

function detectProduct(item) {
  const codename = (item.codename || "").toLowerCase();
  const releaseLabel = (item.releaseLabel || "").toLowerCase();
  const cycle = (item.cycle || "").toLowerCase();
  const link = (item.link || "").toLowerCase();

  if (link.includes("microsoft") || link.includes("windows") || releaseLabel.includes("windows") || cycle.startsWith("10-") || cycle.startsWith("11-")) {
    if (cycle.includes("server") || releaseLabel.includes("server") || ["2025", "2022", "2019", "2016", "2012", "2008", "2003", "2000"].some(yr => cycle.includes(yr))) {
      return { id: "windows-server", name: "Windows Server" };
    }
    return { id: "windows", name: "Windows Desktop" };
  }

  const codenameWords = codename.split(/[\s\-_()]+/);
  const macCodenames = ["tahoe", "sequoia", "sonoma", "ventura", "monterey", "big", "sur", "catalina", "mojave", "high", "sierra", "el", "capitan", "yosemite", "mavericks", "mountain", "lion", "snow", "leopard", "tiger", "panther", "jaguar", "puma", "cheetah"];
  const debianCodenames = ["trixie", "bookworm", "bullseye", "buster", "stretch", "jessie", "wheezy", "squeeze", "lenny", "etch", "sarge", "woody", "potato", "slink", "hamm", "bo", "rex", "buzz"];
  const ubuntuCodenames = ["raccoon", "quokka", "puffin", "oriole", "numbat", "minotaur", "lobster", "kudu", "jellyfish", "indri", "hippo", "gorilla", "fossa", "ermine", "dingo", "cuttlefish", "beaver", "aardvark", "zapus", "yak", "xerus", "werewolf", "vervet", "unicorn", "tahr", "salamander", "ringtail", "quetzal", "pangolin", "ocelot", "narwhal", "meerkat", "lynx", "koala", "jackalope", "ibex", "heron", "gibbon", "fawn", "eft", "drake", "badger", "hedgehog", "warthog"];

  if (codenameWords.some(word => macCodenames.includes(word))) return { id: "macos", name: "macOS" };
  if (codenameWords.some(word => debianCodenames.includes(word))) return { id: "debian", name: "Debian Linux" };
  if (codenameWords.some(word => ubuntuCodenames.includes(word))) return { id: "ubuntu", name: "Ubuntu Linux" };

  if (link.includes("debian") || link.includes("debian.org")) return { id: "debian", name: "Debian Linux" };
  if (link.includes("ubuntu") || link.includes("ubuntu.com")) return { id: "ubuntu", name: "Ubuntu Linux" };
  if (link.includes("apple.com") || releaseLabel.includes("os x") || releaseLabel.includes("mac os")) return { id: "macos", name: "macOS" };
  if (["2025", "2022", "2019", "2016", "2012", "2008", "2003", "2000"].includes(cycle)) return { id: "windows-server", name: "Windows Server" };

  return { id: "unknown", name: "Unknown Product" };
}

const items = $input.all();
const staticData = $getWorkflowStaticData('global');
staticData.sentAlerts = staticData.sentAlerts || {};

const alerts = [];
const today = new Date();

let initProducts = [];
try {
  initProducts = $('Init Products').all();
} catch (e) {
  // Safe fallback
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const cycleInfo = item.json;

  let productInfo = { id: "unknown", name: "Unknown Product" };
  const detected = detectProduct(cycleInfo);

  if (detected.id !== "unknown") {
    productInfo = detected;
  } else {
    try {
      if (item.pairedItem && typeof item.pairedItem.item === 'number') {
        const idx = item.pairedItem.item;
        if (idx >= 0 && idx < initProducts.length) {
          productInfo = initProducts[idx].json;
        }
      } else {
        if (items.length === initProducts.length && i < initProducts.length) {
          productInfo = initProducts[i].json;
        } else if (initProducts.length > 0) {
          productInfo = initProducts[0].json;
        }
      }
    } catch (e) {
      // Keep default fallback
    }
  }

  const productId = productInfo.id;
  const productName = productInfo.name;

  const cycle = cycleInfo.cycle;
  const releaseLabel = cycleInfo.releaseLabel || cycle;
  const eol = cycleInfo.eol;

  if (!eol || typeof eol !== 'string') continue;

  const eolDate = new Date(eol);
  const timeDiff = eolDate.getTime() - today.getTime();
  const daysRemaining = Math.ceil(timeDiff / (1000 * 60 * 60 * 24));

  let activeThreshold = null;
  if (daysRemaining <= 7 && daysRemaining >= 0) {
    activeThreshold = 7;
  } else if (daysRemaining <= 30 && daysRemaining > 7) {
    activeThreshold = 30;
  } else if (daysRemaining <= 60 && daysRemaining > 30) {
    activeThreshold = 60;
  }

  if (activeThreshold !== null) {
    const alertKey = `${productId}_${cycle}_${activeThreshold}`;

    if (!staticData.sentAlerts[alertKey]) {
      alerts.push({
        json: {
          productId,
          productName,
          cycle,
          releaseLabel,
          eolDate: eol,
          daysRemaining,
          threshold: activeThreshold,
          alertKey,
          link: cycleInfo.link || `https://endoflife.date/${productId}`,
          color: activeThreshold === 7 ? 15158332 : (activeThreshold === 30 ? 15105570 : 3447003),
          timestamp: new Date().toISOString()
        }
      });
      staticData.sentAlerts[alertKey] = true;
    }
  }
}

return alerts;

